-- 2026-06-01: knee_itbs — фазы «Путь» + структурированные критерии перехода.
-- Knee protocols, синдром илиотибиального тракта (ITBS). Сидируется по образцу knee_oa.
--
-- Источник: PROTOCOLS/_ext_knee_itbs.json (досье ITBS, консервативный criterion-based путь).
-- Решение Vadim 2026-06-01: ITBS — overuse-компрессионный синдром, НЕ острая травма и НЕ
-- послеоперационный протокол. Привязки к дате операции нет (хирургия крайне редка, последняя
-- линия, протокол в досье отсутствует). 3 фазы: 1 Деирритация и разгрузка → 2 Нагрузка и
-- контроль движения → 3 Возврат к спорту. Фазы 0 в досье нет — нумерация с 1 как есть.
--
-- Прогрессия КРИТЕРИЙ-ЗАВИСИМАЯ, не время-зависимая: переходы по объективным гейтам
-- (24-часовая реакция боли, безболезненная переносимая дистанция, контроль колена при приседе),
-- а недели даны лишь как ориентир. Поэтому duration_weeks — мягкий guardrail, не жёсткий срок.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев (ТЗ §2.3): в досье НЕТ числовых порогов по ROM/силе/обхвату/боли-ВАШ
-- (досье прямо пишет: «единого валидированного ITBS-специфичного опросника нет», гейты
-- сформулированы качественно). Поэтому criterion_type='measurement' НЕ используется вовсе.
-- Качественные «да/нет» от пациента (реакция боли, безболезненная дистанция/активность) →
-- 'self_report'. Очный осмотр движения куратором (контроль колена при приседе, походка/таз) →
-- 'instructor_check'. Числовые ориентиры (каденс +5–10%) — в текст label, без порога.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee_oa/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы knee_itbs (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
(
    'knee_itbs', 1,
    'Деирритация и разгрузка',
    'Обычно первые 1–2 недели',
    '0-2',
    'Боль с наружной стороны колена при ITBS — это раздражение мягких тканей под наружным тяжом бедра. Первый шаг — снять это раздражение: временно уменьшить провоцирующую нагрузку и дать тканям успокоиться. Сроки ориентировочные — двигаемся по самочувствию, а не по календарю.',
    '["Снять раздражение тканей с наружной стороны колена","Стабилизировать симптомы — чтобы боль перестала вспыхивать","Временно снизить нагрузку ниже порога, на котором появляется боль","Начать спокойные упражнения на боковые мышцы бедра без боли"]',
    '["Временно избегать бега под гору — это самая раздражающая нагрузка","Избегать бега по наклонным дорогам и тропам с уклоном вбок","Избегать слишком узкой постановки ног — стопа за стопу","Велосипедистам — снизить объём и при возможности поправить посадку","Относительный покой и снижение нагрузки; боль подсказывает, сколько можно"]',
    '["Повседневные дела даются без боли в колене","Боль не усиливается на следующий день после нагрузки"]',
    'shield', '#10B981', '#EDFAF5',
    'Снять раздражение и успокоить колено',
    '["Относительный покой с уменьшением нагрузки","Спокойные удержания для боковых мышц бедра в безболезненном объёме","Понять, как управлять нагрузкой, чтобы не провоцировать боль","Массажный ролик можно использовать только для короткого облегчения, он не «вправляет» тяж"]',
    '["Боль — главный ориентир, сколько нагрузки можно сегодня","Цель этого этапа — спокойные повседневные движения без боли","Если боль усилилась через сутки после нагрузки — в следующий раз сделайте меньше"]',
    '["Снижайте раздражающую нагрузку, но не лежите без движения","Делайте мягкие упражнения на боковые мышцы бедра каждый день","Слушайте колено: усиление боли назавтра — сигнал сбавить"]',
    '["Колено заклинивает, щёлкает с блокировкой или есть чувство неустойчивости — к врачу","Колено заметно опухло — к врачу","Боль ночью или в полном покое, не связанная с нагрузкой — к врачу","Онемение, покалывание или слабость в голени и стопе — к врачу","Колено стало горячим, красным, поднялась температура — срочно к врачу","Боль в икре и отёк голени — срочно к врачу"]',
    '[{"q":"Нужно ли тянуть и катать ролик по этому тяжу?","a":"Растянуть или «раскатать» сам тяж нельзя — он очень прочный. Ролик помогает лишь на короткое время снять боль. Главное лечение — управление нагрузкой и упражнения на мышцы бедра."},{"q":"Почему именно бег под гору так мешает?","a":"При спуске колено работает в положении, в котором тяж сильнее прижимается к кости и раздражается. Поэтому спуски убираем в первую очередь и возвращаем в последнюю."},{"q":"Сколько продлится этот этап?","a":"Чаще всего 1–2 недели, но точный срок зависит от того, как быстро успокаивается боль. Двигаемся по самочувствию."}]'
),
(
    'knee_itbs', 2,
    'Нагрузка и контроль движения',
    'Обычно несколько недель',
    '2-6',
    'Когда раздражение успокоилось, постепенно возвращаем колену силу и учим его двигаться правильно. Главная задача — укрепить боковые мышцы бедра и таза, чтобы при движении колено не «заваливалось» внутрь. Нагрузку наращиваем так, чтобы назавтра боль не усиливалась.',
    '["Постепенно повышать переносимость нагрузки","Укрепить боковые мышцы бедра и ягодицы","Научиться удерживать колено в правильной линии при движении","Убрать заваливание колена внутрь и проседание таза в сторону"]',
    '["Пока не пройден контроль движения — по-прежнему избегать спусков, наклонных поверхностей и узкого шага","Наращивать нагрузку так, чтобы боль не усиливалась через сутки"]',
    '["При приседе на одной ноге и шаге со ступеньки колено держится ровно, не заваливается внутрь, таз не проседает","Нагрузочные упражнения переносятся без усиления боли на следующий день"]',
    'dumbbell', '#3B82F6', '#EFF7FD',
    'Сила боковых мышц и правильное движение колена',
    '["Упражнения на силу боковых мышц бедра и ягодиц","Постепенная прогрессия: удержания → движения с торможением → разноплановые упражнения","Тренировка контроля колена и таза при движении","Начало работы над техникой ходьбы и движения вне бега"]',
    '["Ориентир — упражнения переносятся без усиления боли на следующий день","Если назавтра после занятия боль выросла — это сигнал сделать шаг назад и снизить нагрузку"]',
    '["Делайте силовые упражнения регулярно, но без боли назавтра","Следите за линией колена в зеркале — оно не должно уходить внутрь","Повышайте нагрузку маленькими шагами"]',
    '["Колено заклинивает, щёлкает с блокировкой или есть чувство неустойчивости — к врачу","Колено заметно опухло — к врачу","Боль ночью или в полном покое — к врачу","Онемение, покалывание или слабость в голени и стопе — к врачу","Если за 6–8 недель занятий нет улучшения — обсудите с врачом, всё ли учтено"]',
    '[{"q":"Зачем тренировать бедро и таз, если болит колено?","a":"Боль в колене при ITBS часто идёт от того, что бедро и таз плохо управляют ногой и колено заваливается внутрь. Укрепив их, мы снимаем нагрузку с раздражённого места."},{"q":"Что значит «шаг назад по фазе»?","a":"Если после занятия боль усилилась на следующий день, мы временно снижаем нагрузку и возвращаемся к более лёгким упражнениям. Это нормальная часть восстановления, а не провал."}]'
),
(
    'knee_itbs', 3,
    'Возврат к спорту',
    'Когда колено готово к нагрузке',
    NULL,
    'Заключительный этап — аккуратно вернуться к бегу или велосипеду и не допустить повторения. Возвращаемся постепенно: сначала по ровной поверхности и небольшими объёмами, затем понемногу увеличиваем. Резкий скачок километража — главная причина рецидива, поэтому добавляем нагрузку маленькими шагами.',
    '["Безболезненно вернуться к привычному спорту","Не допустить повторного появления боли","Закрепить правильную технику движения"]',
    '["Спуски и бег под гору вводить в самую последнюю очередь и очень постепенно","Не увеличивать резко километраж или объём тренировок — это главная причина возврата боли","Начинать бег по ровной поверхности, без спусков"]',
    '["Привычная дистанция при комфортном темпе проходится без боли","Колено и таз остаются под контролем при беге и нагрузке","Боль не усиливается через сутки после пробежки"]',
    'trophy', '#8B5CF6', '#F4F0FD',
    'Постепенный безболезненный возврат к бегу и велоспорту',
    '["Бегунам: чередование бега и ходьбы через день, начиная по ровной поверхности без спусков, с постепенным ростом объёма","Работа над техникой ходьбы и бега: немного более частый шаг (на 5–10% выше привычного)","Чуть шире ставить стопы, если была привычка ставить ногу за ногу","Тренировка контроля таза","Велосипедистам: постепенный рост объёма и закреплённая правильная посадка"]',
    '["Ориентир — после пробежки боль не усиливается на следующий день","Если боль вернулась раньше привычной дистанции — пересмотрите объём и технику","Запоминайте, на какой дистанции появляется боль: это удобный способ отслеживать прогресс"]',
    '["Возвращайте нагрузку маленькими шагами","Спуски — в последнюю очередь и понемногу","Сохраняйте упражнения на силу бедра как профилактику"]',
    '["Боль возвращается каждый раз при попытке вернуться к бегу — расскажите куратору и врачу","Нет улучшения после нескольких недель правильных занятий — нужна врачебная оценка","Появились онемение, слабость в ноге или чувство неустойчивости колена — к врачу"]',
    '[{"q":"Когда можно снова бегать в полную силу?","a":"Когда привычная дистанция в комфортном темпе проходит без боли и без её усиления на следующий день. Объём добавляем постепенно, по самочувствию."},{"q":"Почему нельзя сразу вернуть прежний километраж?","a":"Резкий скачок нагрузки — главная причина повторного раздражения. Маленькие шаги дают тканям время приспособиться."},{"q":"Боль вернулась при возврате к бегу — что делать?","a":"Снизьте объём, вернитесь к более лёгкому режиму и пересмотрите технику с куратором. Иногда нужен повторный осмотр у врача."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода knee_itbs
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (деирритация → нагрузка и контроль движения)
  (1, 'pain_free_daily',     'Повседневные дела даются без боли в колене',                          'self_report'::varchar, NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Повседневные дела даются без боли в колене?'::text, 'Ходьба, лестница, обычные домашние дела'::text, 10::smallint, TRUE),
  (1, 'no_24h_flare_p1',     'Боль не усиливается на следующий день после нагрузки',                'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Усиливается ли боль через сутки после нагрузки?', 'Сравните самочувствие утром после активного дня', 20::smallint, TRUE),
  -- Фаза 2 → Фаза 3 (нагрузка и контроль движения → возврат к спорту)
  (2, 'knee_control_squat',  'Колено держится ровно при приседе на одной ноге и шаге со ступеньки (не заваливается внутрь, таз не проседает)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'no_24h_flare_p2',     'Нагрузочные упражнения переносятся без усиления боли на следующий день', 'self_report',        NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Переносятся ли нагрузочные упражнения без усиления боли назавтра?', 'Ориентируйтесь на самочувствие на следующий день', 20::smallint, TRUE),
  -- Фаза 3 — финальная (возврат к спорту), критериев перехода дальше нет, но фиксируем целевые маркёры
  (3, 'pain_free_distance',  'Привычная дистанция при комфортном темпе проходится без боли',         'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Проходите ли привычную дистанцию в комфортном темпе без боли?', 'Запоминайте дистанцию, на которой появляется боль', 10::smallint, TRUE),
  (3, 'gait_metrics_ok',     'Колено и таз остаются под контролем при беге; техника движения приемлема (частота шага, контроль таза)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, FALSE),
  (3, 'no_24h_flare_p3',     'Боль не усиливается через сутки после пробежки',                       'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Усиливается ли боль через сутки после пробежки?', 'Сравните самочувствие на следующее утро после бега', 30::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'knee_itbs' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
